import{_ as o,o as r,c as a,e as s}from"./app-83da4608.js";const c={};function i(t,e){return r(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="coco-server-后台管理平台-web-代码结构与业务架构说明" tabindex="-1"><a class="header-anchor" href="#coco-server-后台管理平台-web-代码结构与业务架构说明" aria-hidden="true">#</a> Coco Server 后台管理平台（Web）代码结构与业务架构说明</h1><h2 id="_1-技术栈与关键约束" tabindex="-1"><a class="header-anchor" href="#_1-技术栈与关键约束" aria-hidden="true">#</a> 1. 技术栈与关键约束</h2><h3 id="_1-1-技术栈-从-package-json-可验证" tabindex="-1"><a class="header-anchor" href="#_1-1-技术栈-从-package-json-可验证" aria-hidden="true">#</a> 1.1 技术栈（从 package.json 可验证）</h3><ul><li>构建：Vite 5（<code>vite</code>）、TypeScript（<code>tsc</code>）</li><li>UI：Ant Design 5（<code>antd</code>）+ ProComponents（<code>@ant-design/pro-components</code>）</li><li>状态管理：Redux Toolkit（<code>@reduxjs/toolkit</code>）+ React Redux（<code>react-redux</code>）</li><li>路由：<code>@sa/simple-router</code>（基于 React Router v6）+ <code>@ohh-889/react-auto-route</code>（构建期生成路由）</li><li>样式：UnoCSS（<code>@unocss/*</code>）+ SCSS/Less</li><li>网络：Axios（通过工作区包 <code>@sa/axios</code> 封装）</li><li>i18n：i18next + react-i18next</li><li>页面 keep-alive：keepalive-for-react</li></ul><p>源码位置：<a href="/coco-server/web/package.json#L1-L105">package.json</a></p><h3 id="_1-2-重要约束-假设-从实现反推" tabindex="-1"><a class="header-anchor" href="#_1-2-重要约束-假设-从实现反推" aria-hidden="true">#</a> 1.2 重要约束/假设（从实现反推）</h3><ul><li>请求默认带 cookie：<code>@sa/axios</code> 在模块初始化阶段设置 <code>axios.defaults.withCredentials = true</code>，意味着该管理台天然支持“cookie session / httpOnly cookie”这类认证方式，而不是强依赖前端拼接 <code>Authorization</code> header。<br> 源码位置：<a href="/coco-server/web/packages/axios/src/index.ts#L1-L21">web/packages/axios/src/index.ts</a></li><li>路由与菜单是“文件路由 + 元信息”驱动：构建期插件扫描 <code>src/pages</code> 与布局定义生成 <code>src/router/elegant/*</code>，运行时再根据登录态/权限把路由注入 router。</li></ul><hr><h2 id="_2-代码目录结构-按职责分层" tabindex="-1"><a class="header-anchor" href="#_2-代码目录结构-按职责分层" aria-hidden="true">#</a> 2. 代码目录结构（按职责分层）</h2><h3 id="_2-1-顶层-web" tabindex="-1"><a class="header-anchor" href="#_2-1-顶层-web" aria-hidden="true">#</a> 2.1 顶层（/web）</h3><ul><li><code>vite.config.ts</code>：构建输出、依赖拆包、代理、别名、插件装配<br> 入口：<a href="/coco-server/web/vite.config.ts#L1-L75">vite.config.ts</a></li><li><code>build/</code>：Vite 插件与 build-time 配置（代理、HTML 注入、路由生成等）<br> 入口：<a href="/coco-server/web/build/plugins/index.ts#L1-L26">build/plugins/index.ts</a></li><li><code>src/</code>：业务与运行时代码（启动、路由、状态、服务、页面）</li></ul><h3 id="_2-2-运行时核心-web-src" tabindex="-1"><a class="header-anchor" href="#_2-2-运行时核心-web-src" aria-hidden="true">#</a> 2.2 运行时核心（/web/src）</h3><ul><li>启动入口：<code>src/main.tsx</code><br><a href="/coco-server/web/src/main.tsx#L1-L54">main.tsx</a></li><li>应用壳：<code>src/App.tsx</code>（主题/水印/路由容器）<br><a href="/coco-server/web/src/App.tsx#L1-L82">App.tsx</a></li><li>路由：<code>src/router/*</code>（router 实例、guard、routes 装配）</li><li>状态：<code>src/store/*</code>（Redux Toolkit slices）</li><li>请求：<code>src/service/request/*</code> + <code>src/service/api/*</code>（统一 request + API 封装）</li><li>页面：<code>src/pages/*</code>（按业务域拆分）</li><li>布局：<code>src/layouts/*</code>（菜单、头部、内容、keep-alive、tab 等）</li><li>多语言：<code>src/locales/*</code></li><li>微前端适配：<code>src/components/micro/*</code></li></ul><hr><h2 id="_3-构建与开发时架构-vite-插件体系" tabindex="-1"><a class="header-anchor" href="#_3-构建与开发时架构-vite-插件体系" aria-hidden="true">#</a> 3. 构建与开发时架构（Vite + 插件体系）</h2><h3 id="_3-1-vite-配置关键点" tabindex="-1"><a class="header-anchor" href="#_3-1-vite-配置关键点" aria-hidden="true">#</a> 3.1 Vite 配置关键点</h3><ul><li><code>base</code>：来自 <code>VITE_BASE_URL</code></li><li>构建产物：输出到 <code>../.public</code>，用于与后端/同仓库静态目录对接<br><a href="/coco-server/web/vite.config.ts#L18-L34">vite.config.ts</a></li><li>手动拆包：把 <code>@ant-design/pro-*</code> 打到 <code>vendor-antd-pro</code>，其余 node_modules 打到 <code>vendor-core</code>，降低首次加载/缓存失效率<br><a href="/coco-server/web/vite.config.ts#L22-L33">vite.config.ts</a></li><li>Dev server 代理：由 <code>createViteProxy(viteEnv, enableProxy)</code> 决定是否启用（要求 <code>serve</code> 且 <code>VITE_HTTP_PROXY === &#39;Y&#39;</code>）<br><a href="/coco-server/web/vite.config.ts#L63-L74">vite.config.ts</a></li></ul><h3 id="_3-2-代理与-service-baseurl-原理" tabindex="-1"><a class="header-anchor" href="#_3-2-代理与-service-baseurl-原理" aria-hidden="true">#</a> 3.2 代理与 Service BaseURL 原理</h3><p>这套代码同时满足两类运行方式：</p><ol><li>本地开发时，通过 Vite proxy 把前端请求转发到后端（避免跨域/简化 baseURL 配置）。</li><li>生产部署时，前端通常与后端同域（或由网关统一转发），<code>baseURL</code> 直接是当前站点的 <code>origin + pathname</code> 或微前端注入的 proxy endpoint。</li></ol><h4 id="_3-2-1-代理路由前缀的生成规则" tabindex="-1"><a class="header-anchor" href="#_3-2-1-代理路由前缀的生成规则" aria-hidden="true">#</a> 3.2.1 代理路由前缀的生成规则</h4><ul><li>默认服务：<code>/proxy-default</code></li><li>多服务：<code>/proxy-\${key}</code>（<code>key</code> 若以 <code>/</code> 开头则原样视为 pattern）</li></ul><p>实现：<a href="/coco-server/web/src/utils/service.ts#L8-L41">createServiceConfig</a> + <a href="/coco-server/web/src/utils/service.ts#L64-L78">createProxyPattern</a></p><h4 id="_3-2-2-vite-proxy-的-rewrite-规则" tabindex="-1"><a class="header-anchor" href="#_3-2-2-vite-proxy-的-rewrite-规则" aria-hidden="true">#</a> 3.2.2 Vite proxy 的 rewrite 规则</h4><p><code>rewrite</code> 用正则去掉 <code>proxyPattern</code> 前缀；当 <code>key</code> 本身以 <code>/</code> 开头时保留 pattern（用于更自由的路径拼接）。</p><p>实现：<a href="/coco-server/web/build/config/proxy.ts#L11-L25">createViteProxy</a> / <a href="/coco-server/web/build/config/proxy.ts#L27-L38">createProxyItem</a></p><h3 id="_3-3-构建期路由生成-elegant-router-react-auto-route" tabindex="-1"><a class="header-anchor" href="#_3-3-构建期路由生成-elegant-router-react-auto-route" aria-hidden="true">#</a> 3.3 构建期路由生成（Elegant Router / react-auto-route）</h3><p>构建期插件 <code>setupElegantRouter()</code> 会：</p><ul><li>声明布局入口（base/blank）</li><li>从文件路由生成 routeName，并自动生成基础 meta（<code>i18nKey</code> / <code>title</code> / <code>constant</code>）</li><li>输出生成物到 <code>src/router/elegant/*</code>（例如 <code>imports.ts</code>、<code>routes.ts</code>）</li></ul><p>入口：<a href="/coco-server/web/build/plugins/router.ts#L1-L46">build/plugins/router.ts</a></p><p>生成物示例：</p><ul><li>页面懒加载映射：<a href="/coco-server/web/src/router/elegant/imports.ts#L14-L58">src/router/elegant/imports.ts</a></li><li>路由树 + 权限 meta：<a href="/coco-server/web/src/router/elegant/routes.ts#L7-L632">src/router/elegant/routes.ts</a></li></ul><h3 id="_3-4-html-注入-buildtime-元信息" tabindex="-1"><a class="header-anchor" href="#_3-4-html-注入-buildtime-元信息" aria-hidden="true">#</a> 3.4 HTML 注入：buildTime 元信息</h3><p>生产构建时会在 <code>index.html</code> 的 <code>&lt;head&gt;</code> 注入 <code>&lt;meta name=&quot;buildTime&quot; content=&quot;...&quot;&gt;</code>，用于运行时做“版本更新检测”（见 <code>setupAppVersionNotification</code>：通过重新拉取 <code>index.html</code> 解析该 meta，并与编译期常量 <code>BUILD_TIME</code> 比对）。</p><ul><li>注入逻辑：<a href="/coco-server/web/build/plugins/html.ts#L1-L13">build/plugins/html.ts</a></li><li>运行时检测：<a href="/coco-server/web/src/plugins/app.ts#L6-L78">plugins/app.ts</a></li></ul><hr><h2 id="_4-运行时启动链路-从-main-tsx-到可用页面" tabindex="-1"><a class="header-anchor" href="#_4-运行时启动链路-从-main-tsx-到可用页面" aria-hidden="true">#</a> 4. 运行时启动链路（从 main.tsx 到可用页面）</h2><h3 id="_4-1-启动顺序-关键初始化" tabindex="-1"><a class="header-anchor" href="#_4-1-启动顺序-关键初始化" aria-hidden="true">#</a> 4.1 启动顺序（关键初始化）</h3><p><code>setupApp()</code> 的顺序基本体现“用户可感知优先级”：</p><ol><li>i18n 初始化（否则 loading 文案/错误文案不稳定）</li><li>Loading HTML 注入（首屏骨架）</li><li>NProgress 注入到 window（路由切换/请求阶段）</li><li>Iconify 离线源配置（可选）</li><li>Router 初始化（包含 init/guard，决定跳转到 guide/login/home）</li><li>dayjs locale plugin</li><li>判断是否微前端（Wujie）：微前端走 mount/unmount；非微前端开启版本更新提示</li></ol><p>实现：<a href="/coco-server/web/src/main.tsx#L29-L52">main.tsx</a></p><h3 id="_4-2-app-壳层能力-主题-水印-路由容器" tabindex="-1"><a class="header-anchor" href="#_4-2-app-壳层能力-主题-水印-路由容器" aria-hidden="true">#</a> 4.2 App 壳层能力（主题/水印/路由容器）</h3><p><code>App.tsx</code> 核心职责：</p><ul><li>读取主题设置（Redux）并通过 <code>AConfigProvider</code> 注入 AntD theme 与 locale</li><li>设置 CSS 变量与暗色模式开关</li><li>全局水印（可开关）</li><li>渲染 <code>RouterProvider</code>，并提供路由 fallback loading</li></ul><p>实现：<a href="/coco-server/web/src/App.tsx#L26-L79">App.tsx</a></p><h3 id="_4-3-微前端-wujie-适配点" tabindex="-1"><a class="header-anchor" href="#_4-3-微前端-wujie-适配点" aria-hidden="true">#</a> 4.3 微前端（Wujie）适配点</h3><p>当 <code>window.__POWERED_BY_WUJIE__</code> 为真：</p><ul><li><code>main.tsx</code> 不调用版本更新检测，改走 <code>setupMicro(root, renderRoot)</code></li><li><code>setupMicro</code> 暴露 <code>__WUJIE_MOUNT/__WUJIE_UNMOUNT</code> 并调用 <code>window.__WUJIE.mount()</code></li><li>克隆子应用的本地 SVG sprite 到父文档，避免图标丢失</li><li>hook <code>history.pushState/replaceState</code> 通知宿主 <code>onRouteChange</code></li></ul><p>实现：<a href="/coco-server/web/src/components/micro/index.tsx#L1-L55">components/micro/index.tsx</a></p><p>请求域名/代理端点在微前端中也可由宿主注入：</p><ul><li><code>getProxyEndpoint()</code> 读取 <code>window.$wujie.props.proxy_endpoint</code></li></ul><p>实现：<a href="/coco-server/web/src/components/micro/utils.ts#L1-L8">components/micro/utils.ts</a></p><hr><h2 id="_5-路由系统-生成路由-运行时注入-guard" tabindex="-1"><a class="header-anchor" href="#_5-路由系统-生成路由-运行时注入-guard" aria-hidden="true">#</a> 5. 路由系统：生成路由 + 运行时注入 + Guard</h2><h3 id="_5-1-router-实例如何创建" tabindex="-1"><a class="header-anchor" href="#_5-1-router-实例如何创建" aria-hidden="true">#</a> 5.1 router 实例如何创建</h3><p><code>src/router/index.ts</code> 使用 <code>@sa/simple-router</code> 创建 router，并把“Elegant 路由”转换为 React Router v6 的 RouteObject：</p><ul><li><code>layouts/pages</code> 来源于构建期生成的 <code>src/router/elegant/imports.ts</code></li><li><code>transformElegantRouteToReactRoute(...)</code> 负责把 <code>component: &#39;layout.base$view.xxx&#39;</code> 这类表达式转成真正的 lazy import</li><li><code>init</code> / <code>beforeEach</code> / <code>afterEach</code> 用于 guard 与标题设置</li><li><code>builtinRoutes</code> 提供 root / 404 / logout 等基础路由</li></ul><p>实现：<a href="/coco-server/web/src/router/index.ts#L1-L32">router/index.ts</a> + <a href="/coco-server/web/src/router/routes/builtin.ts#L11-L57">routes/builtin.ts</a></p><h3 id="_5-2-init-阶段-决定-去-guide-去-login-去-home" tabindex="-1"><a class="header-anchor" href="#_5-2-init-阶段-决定-去-guide-去-login-去-home" aria-hidden="true">#</a> 5.2 init 阶段：决定“去 guide / 去 login / 去 home”</h3><p><code>guard.init</code> 是应用启动后第一次“全局判定”：</p><ol><li><code>fetchServer()</code> 拉取 <code>/provider/_info</code>，写入 <code>serverSlice.providerInfo</code></li><li>根据 providerInfo 决定要“屏蔽哪些路径”（<code>filterPaths</code>）： <ul><li><code>setup_required</code> 相关：未初始化且非托管 -&gt; 必须走 <code>/guide</code></li><li><code>search_settings.enabled</code> 相关：关闭 search -&gt; 屏蔽 <code>/search</code></li></ul></li><li><code>initConstantRoute()</code>：注入常量路由（静态或后端下发）</li><li>若需 setup：直接返回 <code>{ name: &#39;guide&#39; }</code></li><li>否则拉取 <code>fetchGetUserInfo()</code> 判定登录态： <ul><li>已登录：写本地 <code>userInfo</code>，<code>resetAuth()</code>，<code>initAuthRoute()</code>，必要时从 <code>/login</code> 或 <code>/guide</code> 跳回 <code>/</code></li><li>未登录：清理本地 <code>userInfo</code>，<code>resetAuth()</code>，<code>initAuthRoute()</code>，并对受保护路由重定向到 <code>/login?redirect=...</code></li></ul></li></ol><p>实现：<a href="/coco-server/web/src/router/guard/index.ts#L26-L91">router/guard/index.ts:init</a></p><h3 id="_5-3-beforeeach-阶段-权限判断与-403-404-分流" tabindex="-1"><a class="header-anchor" href="#_5-3-beforeeach-阶段-权限判断与-403-404-分流" aria-hidden="true">#</a> 5.3 beforeEach 阶段：权限判断与 403/404 分流</h3><p>核心判断维度：</p><ul><li>是否常量路由（<code>to.meta.constant</code>）：常量路由不要求登录</li><li>是否登录：取 <code>authSlice.selectUserInfo</code></li><li>权限匹配：<code>to.meta.permissions</code> + <code>to.meta.permissionLogic</code>（默认 and；<code>or</code> 表示任一权限即可）</li><li>“超级角色”（仅静态路由模式生效）：<code>isStaticSuper()</code> 由 <code>VITE_STATIC_SUPER_ROLE</code> 决定</li></ul><p>关键分流：</p><ul><li>登录态访问 <code>/login</code>（且满足特定 path 规则）会 <code>window.location.href=&#39;/&#39;</code> 强制刷新回根</li><li>未登录访问受保护路由：跳转 login 并带 redirect</li><li>已登录但无权限：跳转 403</li></ul><p>实现：<a href="/coco-server/web/src/router/guard/index.ts#L98-L195">router/guard/index.ts:createRouteGuard</a></p><h3 id="_5-4-静态-动态路由模式-route-slice" tabindex="-1"><a class="header-anchor" href="#_5-4-静态-动态路由模式-route-slice" aria-hidden="true">#</a> 5.4 静态/动态路由模式（Route Slice）</h3><p>路由注入由 <code>routeSlice</code> 完成，受两个 env 控制：</p><ul><li><code>VITE_CONSTANT_ROUTE_MODE</code>：常量路由来源（<code>static</code> 或从后端 <code>fetchGetConstantRoutes</code> 拉取）</li><li><code>VITE_AUTH_ROUTE_MODE</code>：鉴权路由来源（<code>static</code>：本地生成路由按权限过滤；<code>dynamic</code>：后端下发 user routes）</li></ul><p>实现：<a href="/coco-server/web/src/store/slice/route/index.ts#L182-L260">store/slice/route/index.ts</a></p><p>静态鉴权路由按权限过滤的核心算法：</p><ul><li><code>filterAuthRoutesByPermissions(routes, permissions)</code> 递归过滤并支持 <code>permissionLogic=or</code></li></ul><p>实现：<a href="/coco-server/web/src/store/slice/route/shared.ts#L43-L68">store/slice/route/shared.ts</a></p><hr><h2 id="_6-状态管理与全局能力注入-redux-antd-app" tabindex="-1"><a class="header-anchor" href="#_6-状态管理与全局能力注入-redux-antd-app" aria-hidden="true">#</a> 6. 状态管理与全局能力注入（Redux + AntD App）</h2><h3 id="_6-1-store-组成" tabindex="-1"><a class="header-anchor" href="#_6-1-store-组成" aria-hidden="true">#</a> 6.1 Store 组成</h3><p>Store 以 slice 组合为主（无手写 combineReducers）：</p><ul><li><code>routeSlice</code>：路由注入、菜单排序、keep-alive cache key、屏蔽路径等</li><li><code>authSlice</code>：登录、用户信息、登出清理</li><li><code>themeSlice</code>：主题色/暗黑/布局设置，负责把 CSS 变量写到 HTML</li><li><code>tabSlice</code>：多标签页（GlobalTab）</li><li><code>appSlice</code>：响应式、sider 折叠、reload flag 等</li><li><code>serverSlice</code>：providerInfo（后端能力/部署形态）与根路由联动</li></ul><p>入口：<a href="/coco-server/web/src/store/index.ts#L1-L27">store/index.ts</a></p><h3 id="_6-2-antd-message-modal-notification-的全局挂载" tabindex="-1"><a class="header-anchor" href="#_6-2-antd-message-modal-notification-的全局挂载" aria-hidden="true">#</a> 6.2 AntD message/modal/notification 的全局挂载</h3><p><code>AppProvider</code> 使用 <code>App.useApp()</code> 把 <code>message/modal/notification</code> 挂载到 <code>window.$message/$modal/$notification</code>，使 service/request 层也能弹错误提示或登出弹窗。</p><p>实现：<a href="/coco-server/web/src/components/stateful/AppProvider.tsx#L8-L40">components/stateful/AppProvider.tsx</a></p><hr><h2 id="_7-页面渲染与-keep-alive-布局层的核心职责" tabindex="-1"><a class="header-anchor" href="#_7-页面渲染与-keep-alive-布局层的核心职责" aria-hidden="true">#</a> 7. 页面渲染与 keep-alive（布局层的核心职责）</h2><h3 id="_7-1-baselayout-统一骨架与微前端裁剪" tabindex="-1"><a class="header-anchor" href="#_7-1-baselayout-统一骨架与微前端裁剪" aria-hidden="true">#</a> 7.1 BaseLayout：统一骨架与微前端裁剪</h3><p>BaseLayout 基于 <code>@sa/materials</code> 的 <code>AdminLayout</code>：</p><ul><li>非微前端：显示 Header/Sider/Breadcrumb/Tab/Footer</li><li>微前端：将这些“宿主已提供的能力”置空，只渲染内容区</li><li>在微前端场景下还会把 <code>nav</code> 与 <code>logout</code> 能力回传给宿主（<code>onMicroMounted</code>）</li></ul><p>实现：<a href="/coco-server/web/src/layouts/base-layout/BaseLayout.tsx#L34-L171">layouts/base-layout/BaseLayout.tsx</a></p><h3 id="_7-2-globalcontent-按路由-key-做-keep-alive" tabindex="-1"><a class="header-anchor" href="#_7-2-globalcontent-按路由-key-做-keep-alive" aria-hidden="true">#</a> 7.2 GlobalContent：按路由 key 做 keep-alive</h3><p>keep-alive 关键点：</p><ul><li><code>cacheKey = (pathname + search)</code> 去掉前缀 <code>/</code> 并把 <code>/</code> 替换为 <code>_</code>，保证每个页面实例可唯一标识</li><li><code>include={cacheKeys}</code>：cacheKeys 来自 <code>routeSlice</code>（从 route meta keepAlive 推导）</li><li>支持 “指定 key 销毁缓存” 与 “reload 刷新缓存”</li></ul><p>实现：<a href="/coco-server/web/src/layouts/modules/global-content/index.tsx#L14-L61">layouts/modules/global-content/index.tsx</a></p><hr><h2 id="_8-请求层-统一-request、错误处理、登出与-token-刷新" tabindex="-1"><a class="header-anchor" href="#_8-请求层-统一-request、错误处理、登出与-token-刷新" aria-hidden="true">#</a> 8. 请求层：统一 request、错误处理、登出与 token 刷新</h2><h3 id="_8-1-request-实例的核心配置" tabindex="-1"><a class="header-anchor" href="#_8-1-request-实例的核心配置" aria-hidden="true">#</a> 8.1 request 实例的核心配置</h3><p><code>request</code> 使用 <code>createFlatRequest</code> 封装，返回 <code>{ data, error, response }</code> 的扁平结构，页面层可用 <code>if (!error)</code> 模式处理。</p><p>关键配置点：</p><ul><li><code>baseURL</code>：dev 代理时用 <code>/proxy-default</code> 之类的 pattern；否则走 <code>getProxyEndpoint()</code>（微前端注入）或当前 origin/pathname</li><li><code>onRequest</code>：dev 模式可注入 <code>X-API-TOKEN</code>（便于本地绕过登录）</li><li><code>isBackendSuccess</code>：以 <code>response.status === 200</code> 判成功</li><li><code>transformBackendResponse</code>：直接返回 <code>response.data</code></li></ul><p>实现：<a href="/coco-server/web/src/service/request/index.ts#L9-L46">service/request/index.ts</a></p><h3 id="_8-2-后端失败-与-网络失败-的处理分工" tabindex="-1"><a class="header-anchor" href="#_8-2-后端失败-与-网络失败-的处理分工" aria-hidden="true">#</a> 8.2 “后端失败”与“网络失败”的处理分工</h3><ul><li>后端失败（HTTP 200 但业务失败语义）：走 <code>onBackendFail</code> -&gt; <code>backEndFail</code></li><li>网络失败/HTTP 错误：走 <code>onError</code> -&gt; <code>handleError</code></li></ul><p>实现：</p><ul><li><a href="/coco-server/web/src/service/request/error.ts#L28-L87">service/request/error.ts</a></li><li><a href="/coco-server/web/src/service/request/error.ts#L90-L130">service/request/error.ts</a></li></ul><h3 id="_8-3-登出与重定向策略-与搜索模式联动" tabindex="-1"><a class="header-anchor" href="#_8-3-登出与重定向策略-与搜索模式联动" aria-hidden="true">#</a> 8.3 登出与重定向策略（与搜索模式联动）</h3><p>登出时会根据当前 hash 路径与 providerInfo 的 search 集成情况，决定回到 <code>/search</code> 还是 <code>/login</code>。</p><p>实现：<a href="/coco-server/web/src/service/request/error.ts#L14-L25">service/request/error.ts:handleLogout</a> + <a href="/coco-server/web/src/store/slice/server/shared.ts#L1-L9">server/shared.ts:getRootRouteIfSearch</a></p><h3 id="_8-4-过期-token-刷新-并发折叠" tabindex="-1"><a class="header-anchor" href="#_8-4-过期-token-刷新-并发折叠" aria-hidden="true">#</a> 8.4 过期 token 刷新（并发折叠）</h3><p>当业务错误码命中 <code>VITE_SERVICE_EXPIRED_TOKEN_CODES</code>：</p><ol><li><code>handleExpiredRequest</code> 只允许同时存在一个 refresh promise（<code>state.refreshTokenFn</code>）</li><li>refresh 成功后重放原请求</li></ol><p>实现：</p><ul><li><a href="/coco-server/web/src/service/request/shared.ts#L21-L47">service/request/shared.ts</a></li><li><a href="/coco-server/web/src/service/request/error.ts#L74-L84">service/request/error.ts</a></li></ul><p>补充：<code>@sa/axios</code> 默认 <code>withCredentials=true</code>，因此平台既支持 cookie session，也可以在需要时通过自定义 header/refresh token 方案扩展；当前 <code>request</code> 的默认 <code>onRequest</code> 并不拼接 <code>Authorization</code>，更偏向“同域 cookie”工作方式。<br> 参考：<a href="/coco-server/web/packages/axios/src/index.ts#L1-L21">web/packages/axios/src/index.ts</a></p><h3 id="_8-5-登录态与-token-当前实现的-主路径-与-备用路径" tabindex="-1"><a class="header-anchor" href="#_8-5-登录态与-token-当前实现的-主路径-与-备用路径" aria-hidden="true">#</a> 8.5 登录态与 token：当前实现的“主路径”与“备用路径”</h3><p>从代码可见，这个管理台同时具备两类认证/会话路径：</p><ul><li>主路径更偏向 cookie session：<code>@sa/axios</code> 全局启用 <code>withCredentials=true</code>，而 <code>service/request/index.ts</code> 的默认 <code>onRequest</code> 并不会为每个请求拼接 <code>Authorization: Bearer ...</code>。<br> 参考：<a href="/coco-server/web/packages/axios/src/index.ts#L1-L21">web/packages/axios/src/index.ts</a> + <a href="/coco-server/web/src/service/request/index.ts#L35-L44">service/request/index.ts</a></li><li>代码里也存在 refresh token 与 Bearer token 的能力，但与当前登录 slice 的“写入方式”并不完全闭环： <ul><li>登录接口返回 <code>access_token</code>（<code>/account/login</code>），登录成功后 <code>authSlice</code> 把 token 放进 Redux state，并把 userInfo 写入 local storage；但看不到把 <code>token/refreshToken</code> 写入 local storage 的逻辑（<code>getToken()</code> 也是从 local storage 读）。<br> 参考：<a href="/coco-server/web/src/service/api/auth.ts#L8-L19">service/api/auth.ts:fetchLogin</a> + <a href="/coco-server/web/src/store/slice/auth/index.ts#L18-L50">authSlice.login</a> + <a href="/coco-server/web/src/store/slice/auth/shared.ts#L1-L10">auth/shared.ts:getToken</a></li><li>refresh token 流程依赖 <code>localStg.get(&#39;refreshToken&#39;)</code>，并在 refresh 成功后写回 <code>token/refreshToken</code>；这更像是“另一条认证路径”或遗留实现（例如某些部署/网关模式需要前端显式维护 token）。<br> 参考：<a href="/coco-server/web/src/service/request/shared.ts#L21-L33">service/request/shared.ts</a> + <a href="/coco-server/web/src/service/api/auth.ts#L47-L60">service/api/auth.ts:fetchRefreshToken</a></li></ul></li></ul><p>结论上，描述这套平台时更准确的表述是：它优先按“同域 cookie session”工作，同时保留了 token/refresh token 的扩展能力（以及 dev 环境 <code>X-API-TOKEN</code> 注入作为调试入口）。</p><hr><h2 id="_9-业务模块划分-页面即边界" tabindex="-1"><a class="header-anchor" href="#_9-业务模块划分-页面即边界" aria-hidden="true">#</a> 9. 业务模块划分（页面即边界）</h2><p>下面按“路由 + 页面目录”把后台核心能力分组（可直接在生成路由映射中验证）。</p><p>路由/页面映射入口：<a href="/coco-server/web/src/router/elegant/imports.ts#L19-L58">router/elegant/imports.ts</a></p><h3 id="_9-1-初始化与登录" tabindex="-1"><a class="header-anchor" href="#_9-1-初始化与登录" aria-hidden="true">#</a> 9.1 初始化与登录</h3><ul><li>初始化向导：<code>/guide</code><br> 入口：<a href="/coco-server/web/src/pages/guide/index.tsx">pages/guide/index.tsx</a>（由 init 阶段 <code>setup_required</code> 决定是否强制跳转）</li><li>登录页：<code>/login</code>（托管模式下支持 SSO 外跳）<br> 入口：<a href="/coco-server/web/src/pages/login/index.tsx">pages/login/index.tsx</a><br> 关键表单：<a href="/coco-server/web/src/pages/login/modules/LoginForm.tsx#L18-L114">LoginForm.tsx</a></li></ul><h3 id="_9-2-ai-llm-配置域" tabindex="-1"><a class="header-anchor" href="#_9-2-ai-llm-配置域" aria-hidden="true">#</a> 9.2 AI/LLM 配置域</h3><ul><li>AI Assistant：<code>/ai-assistant/*</code>（列表/新增/编辑）<br> 列表页实现示例：<a href="/coco-server/web/src/pages/ai-assistant/list/index.tsx#L1-L40">ai-assistant/list/index.tsx</a><br> 路由权限：<code>coco#assistant/*</code><br> 路由定义：<a href="/coco-server/web/src/router/elegant/routes.ts#L41-L91">router/elegant/routes.ts</a></li><li>模型提供商（LLM Provider）：<code>/model-provider/*</code>（列表/新增/编辑）<br> 路由权限：<code>coco#model_provider/*</code></li><li>MCP Server：<code>/mcp-server/*</code>（列表/新增/编辑）<br> 路由权限：<code>coco#mcp_server/*</code></li></ul><p>这些模块通常共同决定“Agent 能力的输入侧配置”，其 CRUD API 统一在 <code>src/service/api/*</code>。</p><h3 id="_9-3-数据接入与内容域" tabindex="-1"><a class="header-anchor" href="#_9-3-数据接入与内容域" aria-hidden="true">#</a> 9.3 数据接入与内容域</h3><ul><li>数据源：<code>/data-source/*</code>（列表/新增/编辑/详情）<br> 列表权限：<code>coco#datasource/search</code><br> 详情模块示例（文档列表/映射管理等）：<br><a href="/coco-server/web/src/pages/data-source/detail/modules/FileManagement.tsx#L1-L30">FileManagement.tsx</a> / <a href="/coco-server/web/src/pages/data-source/detail/modules/MappingManagement.tsx#L1-L10">MappingManagement.tsx</a></li><li>连接器（Connector）：<code>/connector/*</code>（隐藏菜单，作为 settings 的子能力）<br> 路由权限：<code>coco#connector/*</code>（permissionLogic=or）<br> 新建页示例：<a href="/coco-server/web/src/pages/connector/new/index.tsx#L1-L20">connector/new/index.tsx</a></li></ul><h3 id="_9-4-安全域-用户-角色-授权与-api-token" tabindex="-1"><a class="header-anchor" href="#_9-4-安全域-用户-角色-授权与-api-token" aria-hidden="true">#</a> 9.4 安全域（用户/角色/授权与 API Token）</h3><ul><li>用户/角色/授权：<code>/security</code> + <code>/user/*</code> + <code>/role/*</code> + <code>/auth/*</code><br> 权限 key 前缀：<code>generic#security:*</code>（permissionLogic=or 组合显示）</li><li>API Token：<code>/api-token/list</code><br> 页面实现：<a href="/coco-server/web/src/pages/api-token/list/index.tsx#L1-L25">api-token/list/index.tsx</a><br> 对应 API：<a href="/coco-server/web/src/service/api/api-token.ts#L1-L39">service/api/api-token.ts</a></li></ul><h3 id="_9-5-系统与集成域" tabindex="-1"><a class="header-anchor" href="#_9-5-系统与集成域" aria-hidden="true">#</a> 9.5 系统与集成域</h3><ul><li>Settings：<code>/settings</code>（system/connector 等能力入口的聚合）<br> 路由权限：<code>coco#system/read</code> 或 <code>coco#connector/search</code></li><li>Integration：<code>/integration/*</code>（列表/新增/编辑）<br> 路由权限：<code>coco#integration/*</code></li><li>Webhook：<code>/webhook/*</code>（路由树存在但当前 meta 未声明 permissions，具体访问控制可能由后端接口鉴权兜底）<br> 路由定义：<a href="/coco-server/web/src/router/elegant/routes.ts#L596-L631">router/elegant/routes.ts</a></li></ul><hr><h2 id="_10-典型流程拆解-端到端-发生了什么" tabindex="-1"><a class="header-anchor" href="#_10-典型流程拆解-端到端-发生了什么" aria-hidden="true">#</a> 10. 典型流程拆解（端到端“发生了什么”）</h2><h3 id="_10-1-应用冷启动-首次进入站点" tabindex="-1"><a class="header-anchor" href="#_10-1-应用冷启动-首次进入站点" aria-hidden="true">#</a> 10.1 应用冷启动（首次进入站点）</h3><div class="language-mermaid line-numbers-mode" data-ext="mermaid"><pre class="language-mermaid"><code><span class="token keyword">sequenceDiagram</span>
  <span class="token keyword">autonumber</span>
  <span class="token keyword">participant</span> B as Browser
  <span class="token keyword">participant</span> M as main.tsx
  <span class="token keyword">participant</span> R as Router<span class="token text string">(init)</span>
  <span class="token keyword">participant</span> S as /provider/_info
  <span class="token keyword">participant</span> U as /account/profile
  <span class="token keyword">participant</span> Store as Redux<span class="token text string">(store)</span>

  B<span class="token arrow operator">-&gt;&gt;</span>M<span class="token operator">:</span> 加载 bundle
  M<span class="token arrow operator">-&gt;&gt;</span>M<span class="token operator">:</span> setupI18n/setupLoading/setupNProgress/...
  M<span class="token arrow operator">-&gt;&gt;</span>R<span class="token operator">:</span> setupRouter<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token arrow operator">-&gt;</span> router.initReady<span class="token punctuation">(</span><span class="token punctuation">)</span>
  R<span class="token arrow operator">-&gt;&gt;</span>S<span class="token operator">:</span> fetchServer<span class="token punctuation">(</span><span class="token punctuation">)</span>
  S<span class="token arrow operator">--&gt;&gt;</span>R<span class="token operator">:</span> providerInfo
  R<span class="token arrow operator">-&gt;&gt;</span>Store<span class="token operator">:</span> setProviderInfo + setFilterPaths + initConstantRoute
  <span class="token keyword">alt</span> setup_required &amp;&amp; !managed
    R<span class="token arrow operator">--&gt;&gt;</span>B<span class="token operator">:</span> redirect /guide
  <span class="token keyword">else</span> 否则
    R<span class="token arrow operator">-&gt;&gt;</span>U<span class="token operator">:</span> fetchGetUserInfo<span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">alt</span> 已登录
      U<span class="token arrow operator">--&gt;&gt;</span>R<span class="token operator">:</span> userInfo
      R<span class="token arrow operator">-&gt;&gt;</span>Store<span class="token operator">:</span> resetAuth + initAuthRoute
      R<span class="token arrow operator">--&gt;&gt;</span>B<span class="token operator">:</span> 进入 home / 原始路由
    <span class="token keyword">else</span> 未登录
      U<span class="token arrow operator">--&gt;&gt;</span>R<span class="token operator">:</span> error
      R<span class="token arrow operator">-&gt;&gt;</span>Store<span class="token operator">:</span> resetAuth + initAuthRoute
      R<span class="token arrow operator">--&gt;&gt;</span>B<span class="token operator">:</span> redirect /login?redirect=...
    <span class="token keyword">end</span>
  <span class="token keyword">end</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对应实现：<a href="/coco-server/web/src/main.tsx#L29-L52">main.tsx</a> + <a href="/coco-server/web/src/router/guard/index.ts#L26-L91">guard.init</a></p><h3 id="_10-2-路由与菜单如何-按权限可见" tabindex="-1"><a class="header-anchor" href="#_10-2-路由与菜单如何-按权限可见" aria-hidden="true">#</a> 10.2 路由与菜单如何“按权限可见”</h3><p>静态路由模式下（<code>VITE_AUTH_ROUTE_MODE=static</code>）：</p><ol><li>构建期生成完整路由树（含 meta.permissions）</li><li>登录后读取 <code>userInfo.permissions</code></li><li><code>filterAuthRoutesByPermissions</code> 递归裁剪路由树</li><li><code>router.addReactRoutes(sortRoutes)</code> 注入可访问的路由</li><li>菜单/Tab/keep-alive 都基于这棵“已裁剪”的路由树工作</li></ol><p>关键实现链路：</p><ul><li><a href="/coco-server/web/src/store/slice/route/index.ts#L249-L260">initAuthRoute</a></li><li><a href="/coco-server/web/src/store/slice/route/shared.ts#L43-L68">filterAuthRoutesByPermissions</a></li><li><a href="/coco-server/web/src/router/guard/index.ts#L123-L176">createRouteGuard 权限判断</a></li></ul><h3 id="_10-3-列表页常见的-搜索-表格-批量操作-模式" tabindex="-1"><a class="header-anchor" href="#_10-3-列表页常见的-搜索-表格-批量操作-模式" aria-hidden="true">#</a> 10.3 列表页常见的“搜索 + 表格 + 批量操作”模式</h3><p>多个业务模块采用类似的数据模型与交互：</p><ul><li>UI 层发起 <code>_search</code> 请求（通常带分页、filter）</li><li>后端返回 ES 风格的 <code>{ hits: { hits: [...] } }</code> 时，统一用 <code>formatESSearchResult</code> 抹平为 <code>{ data, total, took, aggregations }</code></li><li>表格组件直接消费 <code>data/total</code>，并把 filter/keyword 同步到 query string（<code>useQueryParams</code>）</li></ul><p>通用转换：<a href="/coco-server/web/src/service/request/es.ts#L1-L43">formatESSearchResult</a></p><p>示例页面（任取一类即可看到类似结构）：</p><ul><li><a href="/coco-server/web/src/pages/ai-assistant/list/index.tsx">ai-assistant/list</a></li><li><a href="/coco-server/web/src/pages/model-provider/list/index.tsx">model-provider/list</a></li><li><a href="/coco-server/web/src/pages/api-token/list/index.tsx">api-token/list</a></li></ul><hr><h2 id="_11-与后端能力的耦合点-从前端可见的-契约" tabindex="-1"><a class="header-anchor" href="#_11-与后端能力的耦合点-从前端可见的-契约" aria-hidden="true">#</a> 11. 与后端能力的耦合点（从前端可见的“契约”）</h2><h3 id="_11-1-权限-key-命名与路由-meta-permissions" tabindex="-1"><a class="header-anchor" href="#_11-1-权限-key-命名与路由-meta-permissions" aria-hidden="true">#</a> 11.1 权限 key 命名与路由 meta.permissions</h3><p>路由 meta 中出现的权限 key（例如 <code>coco#assistant/search</code>、<code>generic#security:user/search</code>）是前端“可见性/可访问性”的第一道门槛；真正的安全边界仍应由后端接口鉴权兜底。</p><p>可见位置：<a href="/coco-server/web/src/router/elegant/routes.ts#L41-L555">router/elegant/routes.ts</a></p><h3 id="_11-2-providerinfo-驱动的-ui-模式切换" tabindex="-1"><a class="header-anchor" href="#_11-2-providerinfo-驱动的-ui-模式切换" aria-hidden="true">#</a> 11.2 ProviderInfo 驱动的 UI 模式切换</h3><p>providerInfo 至少影响：</p><ul><li>是否必须走初始化向导（<code>setup_required</code> / <code>managed</code>）</li><li>是否开放 <code>/search</code>（<code>search_settings.enabled</code>）</li><li>根路由是否切换为 <code>search</code>（<code>search_settings.integration</code>）</li></ul><p>实现：<a href="/coco-server/web/src/router/guard/index.ts#L26-L52">guard.init</a> + <a href="/coco-server/web/src/store/slice/server/index.ts#L17-L46">serverSlice</a></p><hr><h2 id="_12-快速定位问题的导航-从现象到文件" tabindex="-1"><a class="header-anchor" href="#_12-快速定位问题的导航-从现象到文件" aria-hidden="true">#</a> 12. 快速定位问题的导航（从现象到文件）</h2><ul><li>首屏进了 guide / login / home？看：<a href="/coco-server/web/src/router/guard/index.ts#L26-L91">router/guard/index.ts:init</a></li><li>某个菜单不显示/路由进不去？看： <ul><li>路由 meta.permissions：<a href="/coco-server/web/src/router/elegant/routes.ts">router/elegant/routes.ts</a></li><li>静态过滤逻辑：<a href="/coco-server/web/src/store/slice/route/shared.ts#L43-L68">route/shared.ts</a></li><li>beforeEach 权限判断：<a href="/coco-server/web/src/router/guard/index.ts#L123-L176">router/guard/index.ts</a></li></ul></li><li>API 请求 baseURL 不对/跨域？看： <ul><li>baseURL 推导：<a href="/coco-server/web/src/service/request/index.ts#L9-L14">service/request/index.ts</a></li><li>dev proxy：<a href="/coco-server/web/build/config/proxy.ts#L11-L38">build/config/proxy.ts</a></li><li>微前端 proxy_endpoint：<a href="/coco-server/web/src/components/micro/utils.ts#L1-L8">components/micro/utils.ts</a></li></ul></li></ul>`,161)])])}const n=o(c,[["render",i],["__file","web-admin-architecture.html.vue"]]);export{n as default};
